const items = $input.all();
const item = items[0].json;
const msg = item.body || item;
const message = (msg.message || '').toLowerCase();
const from = msg.from || 'anonymous';

const responses = {
  'hello': 'Hello! Welcome to Ummies Essence! How can I help you today? I can help with: Product prices, Check stock, Delivery info',
  'hi': 'Hi there! Welcome to Ummies Essence! What brings you here today?',
  'help': 'I can help you with: Product information, Pricing, Stock availability, Delivery information, Payment options (M-Pesa). Just ask me anything!',
  'price': 'I can check product prices for you! Which perfume are you interested in? Popular options: Yara, Khamrah, 9PM, Oud for Glory',
  'delivery': 'We deliver throughout Kenya! Nairobi: Same-day or next-day. Other areas: 2-3 business days. Shipping costs calculated at checkout.',
  'payment': 'We accept: M-Pesa (STK Push) - Fastest, Cash on delivery, Bank transfer. M-Pesa is our recommended option!',
  'stock': 'I can check if a product is in stock for you! Which perfume would you like to know about?',
  'order': 'To place an order: 1. Browse products on our website, 2. Add to cart and checkout with M-Pesa, 3. Or message us on WhatsApp for assisted ordering.',
  'whatsapp': 'You can reach us on WhatsApp for quick responses. We can send product photos, process orders, track deliveries, and answer questions.',
  'bye': 'Thank you for chatting with us! Visit our website anytime or WhatsApp us for quick assistance. Have a wonderful day!',
  'thank': 'You are very welcome! Is there anything else I can help you with?',
  'thanks': 'You are very welcome! Is there anything else I can help you with?',
  'yara': 'Yara is a popular fragrance! Let me check the current price and availability for you.',
  'khamrah': 'Khamrah is one of our bestsellers! Let me check the current price and availability for you.',
  '9pm': '9PM is a great choice! Let me check the current price and availability for you.',
  'oud': 'We have several Oud fragrances! Which one are you interested in? Oud for Glory, Oud Touch, or another?',
  'men': 'We have a great selection of mens fragrances! Popular options: Khamrah, 9PM, Oud for Glory. Would you like recommendations?',
  'women': 'We have a beautiful selection of womens fragrances! Popular options: Yara, various floral scents. Would you like recommendations?',
  'unisex': 'Unisex fragrances are versatile and can be worn by anyone! Would you like some recommendations?',
  'perfume': 'We have a wide range of perfumes for men, women, and unisex. What type of fragrance are you looking for?'
};

let responseText = '';
for (const [keyword, resp] of Object.entries(responses)) {
  if (message.includes(keyword)) {
    responseText = resp;
    break;
  }
}

if (!responseText) {
  responseText = 'Thank you for your message! I am here to help with: Product information and pricing, Order placement and tracking, Delivery questions, Payment options (M-Pesa). What can I assist you with today?';
}

return [{
  json: {
    response: responseText,
    originalMessage: msg.message,
    from: from,
    timestamp: new Date().toISOString()
  }
}];
